%[text] # 例9.1（ベクトル量子化）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2026a
%[text] ## 準備
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example09_01"; % mfilename

rng(0)
close all
%%
%[text] ## データ集合の生成
nDim = 2;
nClusters = 5;

% クラスタ中心・サンプル数・広がりに偏りをつける
means = [0.0 0.0; 3.5 1.5; -0.5 3; -2.5 -0.5; 1 -3];
sigmas = [0.7 0.5 0.8 0.6 0.4];
nSamples = [50 30 60 20 40];
sum(nSamples) %[output:6ca4d6c6]
X = [];
trueLabels = [];
for k = 1:nClusters
    X = [X; means(k,:) + sigmas(k) * randn(nSamples(k), nDim)]; %#ok<AGROW>
    trueLabels = [trueLabels; k * ones(nSamples(k), 1)]; %#ok<AGROW>
end
%%
%[text] ## 描画の準備
axLim = [-5 5 -5 5];
%%
%[text] ## データ集合とコードベクトル
figure(1) %[output:45487ea9]
ax1 = axes; %[output:45487ea9]
hold on %[output:45487ea9]
scatter(X(:,1), X(:,2), 15, .5*[1 1 1], 'filled'); %[output:45487ea9]
xlabel('$[\mathbf{x}]_1$','Interpreter','latex'); %[output:45487ea9]
ylabel('$[\mathbf{x}]_2$','Interpreter','latex'); %[output:45487ea9]
%legend([arrayfun(@(k) sprintf('クラスタ%d',k), 1:nCodeVectors, 'UniformOutput', false), {'コードベクトル'}], ...
%    'Location','best')
hold off %[output:45487ea9]
axis equal %[output:45487ea9]
axis(axLim) %[output:45487ea9]
ax1.FontSize = 14; %[output:45487ea9]
ax1.XTick = []; %[output:45487ea9]
ax1.YTick = []; %[output:45487ea9]
ax1.Box = "on"; %[output:45487ea9]
exportgraphics(ax1, fullfile(resfolder,'fig09-01a.png')) %[output:45487ea9]
%%
%[text] ## ベクトル量子化（k-means）
nCodeVectors = nClusters;
[clusterIdx, codeVectors] = kmeans(X, nCodeVectors);
%[text] ## ボロノイ図
figure(2) %[output:7c7db18f]
grayLevels = linspace(0.1, 0.2, nCodeVectors);
ax2 = axes; %[output:7c7db18f]
hold on %[output:7c7db18f]
[vx, vy] = voronoi(codeVectors(:,1), codeVectors(:,2));
plot(vx, vy, 'Color', [0.3 0.3 0.3], 'LineWidth', 1) %[output:7c7db18f]
for k = 1:nCodeVectors
    mask = clusterIdx == k;
    g = grayLevels(k);
    scatter(X(mask,1), X(mask,2), 15, [g g g], 'filled', ... %[output:7c7db18f]
        'MarkerFaceAlpha', 0.2);%, 'Marker', markerStyles{k}) %[output:7c7db18f]
end
scatter(codeVectors(:,1), codeVectors(:,2), 100, 'k', 'x', 'LineWidth', 2) %[output:7c7db18f]
hold off %[output:7c7db18f]
xlabel('$[\mathbf{c}]_1$','Interpreter','latex'); %[output:7c7db18f]
ylabel('$[\mathbf{c}]_2$','Interpreter','latex'); %[output:7c7db18f]
axis equal %[output:7c7db18f]
axis(axLim) %[output:7c7db18f]
ax2.Box = "on"; %[output:7c7db18f]
ax2.XTick = []; %[output:7c7db18f]
ax2.YTick = []; %[output:7c7db18f]
ax2.FontSize = 14; %[output:7c7db18f]
exportgraphics(ax2, fullfile(resfolder,'fig09-01b.png')) %[output:7c7db18f]
